 1	import * as React from 'react';
 2	import cx from 'classnames';
 3	import { useTranslation } from 'react-i18next';
 4	import { Label, LabelGroup } from '@patternfly/react-core';
 5	import {
 6	  ApprovalTaskKind,
 7	  ApproverInput,
 8	  ApprovalStatus,
 9	} from '../../../types';
10	import { ApprovalStatusIcon } from '../../pipeline-topology/StatusIcons';
11	
12	import './ApproverList.scss';
13	import { Approver } from '../../../types/approver';
14	
15	export interface ApproverListProps {
16	  obj: ApprovalTaskKind;
17	}
18	
19	export interface ApproverBadgeProps {
20	  approver: Approver;
21	  status: ApproverInput;
22	}
23	
24	const ApproverBadge: React.FC<ApproverBadgeProps> = ({ approver, status }) => {
25	  const { t } = useTranslation('plugin__pipelines-console-plugin');
26	  const badgeClass = cx({
27	    'pipelines-approval-approver__wait': status === ApprovalStatus.RequestSent,
28	    'pipelines-approval-approver__approved':
29	      status !== ApprovalStatus.RequestSent,
30	  });
31	
32	  const color =
33	    status === ApprovalStatus.RequestSent
34	      ? 'orange'
35	      : status === ApprovalStatus.Accepted
36	      ? 'green'
37	      : 'red';
38	
39	  return (
40	    <Label
41	      className="pipelines-approval-status-badge"
42	      color={color}
43	      icon={
44	        <div className={badgeClass}>
45	          <svg width={30} height={30} viewBox="-12 -5 30 30">
46	            <ApprovalStatusIcon status={status} />
47	          </svg>
48	        </div>
49	      }
50	    >
51	      {approver.type === 'Group'
52	        ? t('Group') + ': ' + approver.name.replace('group:', '')
53	        : t('User') + ': ' + approver.name}
54	    </Label>
55	  );
56	};
57	
58	const ApproverListSection: React.FC<ApproverListProps> = ({ obj }) => {
59	  const { t } = useTranslation('plugin__pipelines-console-plugin');
60	  const {
61	    spec: { approvers },
62	  } = obj;
63	  if (!approvers || approvers?.length === 0) {
64	    return <p>{t('No approvers')}</p>;
65	  }
66	
67	  return (
68	    <LabelGroup
69	      defaultIsOpen
70	      numLabels={10}
71	      className="pipelines-approval-approver-list"
72	    >
73	      {approvers?.map((approver, idx) => (
74	        <ApproverBadge
75	          approver={approver}
76	          status={approver.input}
77	          key={`approver-${idx.toString()}`}
78	        />
79	      ))}
80	    </LabelGroup>
81	  );
82	};
83	
84	export default ApproverListSection;

